mapper.select:
SELECT cl.user_id, cl.comment_id, cl.liked_at AS likedAt,
       u.username, u.avatar_url AS userAvatar,
       uc.content AS commentContent
FROM comment_likes cl
LEFT JOIN users u ON cl.user_id = u.id
LEFT JOIN user_comments uc ON cl.comment_id = uc.id

    AND cl.user_id = #{userId}

        AND u.username LIKE CONCAT('%', #{username}, '%')


        AND cl.liked_at >= #{startTime}


        AND cl.liked_at <= #{endTime}


ORDER BY cl.liked_at DESC
LIMIT #{offset}, #{limit}

SELECT COUNT(*) FROM comment_likes cl
LEFT JOIN users u ON cl.user_id = u.id

    AND cl.user_id = #{userId}

        AND u.username LIKE CONCAT('%', #{username}, '%')


        AND cl.liked_at >= #{startTime}


        AND cl.liked_at <= #{endTime}
